// CRC-32 Calculator
module register_with_enable_reset (
    input clk,
    input enable,
    input reset,
    input [15:0] data_in,
    output reg [15:0] data_out
);

    always @(posedge clk or posedge reset) begin
        if (reset)
            data_out <= 16'b0;
        else if (enable)
            data_out <= data_in;
    end

endmodule
